// Extract relevant fields from Calendly webhook payload
const payload = $input.first().json.payload;
const invitee = payload.invitee || {};
const event = payload.event || {};
const questions = payload.questions_and_answers || [];
const tracking = payload.tracking || {};

// ── Closer assignment from Calendly account ──
// Each Calendly account belongs to one closer.
// event_memberships contains the host's user URI with their UUID.
const CLOSER_MAP = {
  'c983b509-df1c-4661-aad5-8fb7bf40f8c4': 'Juan Martín',
  '908bf103-caf3-4476-92f6-4083ad615ab8': 'Agustín',
};

let closer = '';
const memberships = event.event_memberships || [];
for (const m of memberships) {
  const userUri = m.user || '';
  for (const [uuid, name] of Object.entries(CLOSER_MAP)) {
    if (userUri.includes(uuid)) {
      closer = name;
      break;
    }
  }
  if (closer) break;
}
// Fallback: check event_type owner too
if (!closer) {
  const eventTypeUri = (payload.event_type?.uri || event.uri || '');
  for (const [uuid, name] of Object.entries(CLOSER_MAP)) {
    if (eventTypeUri.includes(uuid)) {
      closer = name;
      break;
    }
  }
}

// ── UTM params ──
const utmSource = tracking.utm_source || '';
const utmMedium = tracking.utm_medium || '';
const utmCampaign = tracking.utm_campaign || '';

// Extract setter from utm_campaign (format: setter_campaign or just setter)
const setter = utmCampaign.includes('_') ? utmCampaign.split('_')[0] : utmCampaign;

// ── Event date ──
const startTime = event.start_time ? new Date(event.start_time) : new Date();
const fechaAgenda = startTime.toISOString().split('T')[0];
const today = new Date();
const mes = `${today.getFullYear()}-${today.getMonth() + 1}`;

// ── Custom questions ──
const igQuestion = questions.find(q => 
  q.question.toLowerCase().includes('instagram') ||
  q.question.toLowerCase().includes('ig')
);
const instagram = igQuestion ? igQuestion.answer : '';

const contextQuestion = questions.find(q => 
  q.question.toLowerCase().includes('contexto') ||
  q.question.toLowerCase().includes('nota') ||
  q.question.toLowerCase().includes('comentario') ||
  q.question.toLowerCase().includes('tell us')
);
const contextoSetter = contextQuestion ? contextQuestion.answer : '';

return [{
  json: {
    nombre: invitee.name || '',
    instagram: instagram,
    fechaLlamada: '',
    fechaAgenda: fechaAgenda,
    setter: setter,
    closer: closer,
    estado: '',
    sePresentó: '',
    calificado: '',
    programa: '',
    contextoSetter: contextoSetter,
    contextoCloser: '',
    cashDia1: '',
    cashTotal: '',
    ticketTotal: '',
    planPago: '',
    pago1: '',
    estadoPago1: '',
    pago2: '',
    estadoPago2: '',
    pago3: '',
    estadoPago3: '',
    saldoPendiente: '',
    fechaPago1: '',
    metodoPago: '',
    fuente: utmSource,
    medioAgenda: utmMedium,
    email: invitee.email || '',
    telefono: '',
    mes: mes,
    calendlyEventUri: event.uri || '',
    calendlyInviteeUri: invitee.uri || '',
    eventTypeName: payload.event_type?.name || ''
  }
}];
